def n_asal(n):
    def asal(x):
        if x < 2:
            return False
        d = 2
        while d * d <= x:
            if x % d == 0:
                return False
            d += 1
        return True
    sayi = 1
    bulunan = 0
    while bulunan < n:
        sayi += 1
        if asal(sayi):
            bulunan += 1
    return sayi
